1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	function cellKey([x, y]: Cell): string {
10	  return `${x},${y}`;
11	}
12	
13	function neighborsOf([x, y]: Cell): Cell[] {
14	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
15	}
16	
17	function countLiveNeighbors(liveCells: Cell[]): Map<string, { cell: Cell; count: number }> {
18	  const counts = new Map<string, { cell: Cell; count: number }>();
19	  for (const cell of liveCells) {
20	    for (const neighbor of neighborsOf(cell)) {
21	      const k = cellKey(neighbor);
22	      const entry = counts.get(k) ?? { cell: neighbor, count: 0 };
23	      entry.count += 1;
24	      counts.set(k, entry);
25	    }
26	  }
27	  return counts;
28	}
29	
30	export function nextGeneration(liveCells: Cell[]): Cell[] {
31	  const liveKeys = new Set(liveCells.map(cellKey));
32	  return Array.from(countLiveNeighbors(liveCells).values())
33	    .filter(({ cell, count }) => count === 3 || (count === 2 && liveKeys.has(cellKey(cell))))
34	    .map(({ cell }) => cell);
35	}
