18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should oscillate a vertical blinker to horizontal (survival + reproduction)", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const result = nextGeneration(vertical);
23	    expect(result).toHaveLength(3);
24	    expect(result).toEqual(expect.arrayContaining<[number, number]>([[-1, 1], [0, 1], [1, 1]]));
